// Generate personalized email content based on user data
const user = $input.first().json;

// Email templates based on user goals
const emailTemplates = {
  'weight_loss': {
    subject: `Hi ${user.name || 'there'}! Missing meals today? Let's get back on track! 🥗`,
    content: `Hello ${user.name || 'there'}!

I noticed you haven't logged any meals yet today. Proper nutrition is key to reaching your weight loss goals!

Here are some quick, healthy meal ideas:
• Breakfast: Greek yogurt with berries and nuts (300 cal)
• Lunch: Grilled chicken salad with mixed vegetables (350 cal)
• Dinner: Baked fish with quinoa and steamed veggies (400 cal)

Remember: Consistency is more important than perfection. Even one logged meal is better than none!

Click here to log your meal now: [Your App Link]

Stay motivated! 💪

Your CalAI Health Coach`
  },
  'muscle_gain': {
    subject: `Hey ${user.name || 'there'}! Time to fuel those gains! 🏋️‍♂️`,
    content: `Hello ${user.name || 'there'}!

I see you haven't logged your meals today. Proper nutrition is crucial for muscle building and recovery!

Today's protein-packed meal suggestions:
• Breakfast: 4 eggs + whole wheat toast + protein shake (600 cal, 40g protein)
• Lunch: Chicken breast + brown rice + broccoli (500 cal, 45g protein)
• Dinner: Lean beef + sweet potatoes + asparagus (600 cal, 50g protein)

Don't forget your post-workout nutrition! Aim for 1.6-2.2g protein per kg bodyweight daily.

Log your meals here: [Your App Link]

Let's build that strength! 🚀

Your CalAI Health Coach`
  },
  'maintain': {
    subject: `Hi ${user.name || 'there'}! Let's maintain that healthy balance! ⚖️`,
    content: `Hello ${user.name || 'there'}!

I noticed you haven't logged any meals today. Consistent meal tracking helps you maintain your current healthy weight and energy levels!

Balanced meal ideas for today:
• Breakfast: Oatmeal with fruits and almonds (400 cal)
• Lunch: Turkey wrap with vegetables (450 cal)
• Dinner: Stir-fried vegetables with tofu (400 cal)

Regular meal logging helps you stay aware of your nutrition patterns and make better choices.

Log your meals here: [Your App Link]

Keep up the great work! 🌟

Your CalAI Health Coach`
  },
  'default': {
    subject: `Hi ${user.name || 'there'}! Don't forget to log your meals today! 📝`,
    content: `Hello ${user.name || 'there'}!

I noticed you haven't logged any meals yet today. Regular meal tracking is the foundation of good health management!

Quick meal logging tips:
• Even a rough estimate is better than nothing
• Try to log within 30 minutes of eating
• Include portion sizes when possible
• Don't forget snacks and drinks!

Consistent tracking helps me provide better personalized advice and track your progress.

Log your meals now: [Your App Link]

Your health journey matters! 💚

Your CalAI Health Coach`
  }
};

// Get user's goal or use default
const userGoal = user.goal || 'default';
const template = emailTemplates[userGoal] || emailTemplates['default'];

// Personalize content
const personalizedContent = template.content
  .replace(/\[Your App Link\]/g, 'https://your-app-url.com/meal-logging')
  .replace(/\$\{name\}/g, user.name || 'there');

return [{
  json: {
    to: user.email,
    subject: template.subject,
    content: personalizedContent,
    user_name: user.name,
    user_goal: user.goal,
    meal_count_today: user.meal_count_today
  }
}];

// Generate positive reinforcement email for active users
const user = $input.first().json;

const positiveTemplates = {
  'weight_loss': {
    subject: `Great job today, ${user.name || 'there'}! Keep up the momentum! 🔥`,
    content: `Hello ${user.name || 'there'}!

Fantastic work! You've logged ${user.meal_count_today} meal(s) today. That's exactly the kind of consistency that drives results!

Your dedication to tracking shows you're serious about your weight loss goals. Here's why this matters:
• You're building healthy habits that last
• You're becoming more mindful of your food choices
• You're creating accountability for yourself

Quick tip: Try to include at least 20g of protein with each meal to stay full longer!

Keep crushing it! 💪

Your CalAI Health Coach`
  },
  'muscle_gain': {
    subject: `Excellent fueling today, ${user.name || 'there'}! 💪`,
    content: `Hello ${user.name || 'there'}!

Awesome job logging ${user.meal_count_today} meal(s) today! Proper nutrition tracking is key to maximizing your muscle gains!

You're doing great because:
• You're ensuring adequate protein intake
• You're tracking your calorie surplus effectively
• You're building the foundation for serious gains

Pro tip: Aim for 20-30g of protein every 3-4 hours for optimal muscle protein synthesis!

Let's get stronger together! 🏋️‍♂️

Your CalAI Health Coach`
  },
  'default': {
    subject: `Well done today, ${user.name || 'there'}! 🌟`,
    content: `Hello ${user.name || 'there'}!

Great job logging ${user.meal_count_today} meal(s) today! Consistent tracking is the foundation of health success!

You're building important habits:
• Increased awareness of your eating patterns
• Better portion control
• Data for personalized health insights

Keep up this excellent consistency. Every logged meal is a step toward better health!

Your dedication inspires us! 🎯

Your CalAI Health Coach`
  }
};

// Only send positive emails every other day to avoid spam
const today = new Date().getDay();
const shouldSendPositive = today % 2 === 0; // Every other day

if (!shouldSendPositive) {
  return [];
}

const userGoal = user.goal || 'default';
const template = positiveTemplates[userGoal] || positiveTemplates['default'];

const personalizedContent = template.content
  .replace(/\[Your App Link\]/g, 'https://your-app-url.com/dashboard')
  .replace(/\$\{name\}/g, user.name || 'there');

return [{
  json: {
    to: user.email,
    subject: template.subject,
    content: personalizedContent,
    user_name: user.name,
    user_goal: user.goal,
    meal_count_today: user.meal_count_today
  }
}];
